mapper.select:
select coalesce(nullif(poa.nx_poa_gb_department_id, 0), poa.nx_poa_department_id) as departmentId, max(coalesce(gd.gb_department_name, nd.nx_department_name)) as departmentName, max(coalesce(gd.gb_department_name, nd.nx_department_order_code)) as departmentOrderCode, sum(case when poa.nx_poa_assign_status = 'PENDING' then 1 else 0 end) as pendingLineCount, sum(case when poa.nx_poa_assign_status = 'ASSIGNED' then 1 else 0 end) as assignedLineCount, count(*) as totalLineCount, group_concat(poa.nx_poa_order_id order by poa.nx_poa_order_id separator ',') as orderIdsCsv, date_format(min(poa.nx_poa_created_at), '%Y-%m-%d %H:%i:%s') as firstPendingAt, date_format(max(poa.nx_poa_created_at), '%Y-%m-%d %H:%i:%s') as lastPendingAt from nx_platform_order_assign poa inner join nx_department_orders dor on dor.nx_department_orders_id = poa.nx_poa_order_id left join gb_department gd on gd.gb_department_id = coalesce(nullif(poa.nx_poa_gb_department_id, 0), poa.nx_poa_department_id) left join nx_department nd on nd.nx_department_id = poa.nx_poa_department_id where poa.nx_poa_market_id = #{marketId} and poa.nx_poa_assign_mode = 'PLATFORM' and poa.nx_poa_assign_status in ('PENDING', 'ASSIGNED') and dor.nx_DO_status >= 0
and dor.nx_DO_apply_date = #{applyDate}
group by coalesce(nullif(poa.nx_poa_gb_department_id, 0), poa.nx_poa_department_id) order by lastPendingAt desc, departmentId asc

select dor.nx_department_orders_id as orderId, poa.nx_poa_id as platformAssignId, dor.nx_DO_nx_goods_id as nxGoodsId, dor.nx_DO_goods_name as goodsName, dor.nx_DO_quantity as quantity, dor.nx_DO_standard as standard, dor.nx_DO_remark as remark, poa.nx_poa_assign_status as assignStatus, poa.nx_poa_assign_mode as assignMode, poa.nx_poa_assign_source as assignSource, poa.nx_poa_assigned_distributer_id as assignedDistributerId, poa.nx_poa_assigned_dis_goods_id as assignedDisGoodsId, ndis.nx_distributer_name as assignedDistributerName, dor.nx_DO_price as orderPrice, dor.nx_DO_subtotal as orderSubtotal, dngd.nx_dngd_id as defaultId, dngd.nx_dngd_default_distributer_id as defaultDistributerId, dngd.nx_dngd_default_dis_goods_id as defaultDisGoodsId, dngd.nx_dngd_source as defaultSource from nx_platform_order_assign poa inner join nx_department_orders dor on dor.nx_department_orders_id = poa.nx_poa_order_id left join nx_distributer ndis on ndis.nx_distributer_id = poa.nx_poa_assigned_distributer_id left join nx_department_nx_goods_default dngd on dngd.nx_dngd_market_id = poa.nx_poa_market_id and dngd.nx_dngd_department_id = coalesce(nullif(poa.nx_poa_gb_department_id, 0), poa.nx_poa_department_id) and dngd.nx_dngd_nx_goods_id = dor.nx_DO_nx_goods_id and dngd.nx_dngd_status = 'ACTIVE' where poa.nx_poa_market_id = #{marketId} and poa.nx_poa_assign_mode = 'PLATFORM' and poa.nx_poa_assign_status in ('PENDING', 'ASSIGNED') and dor.nx_DO_status >= 0 and ( coalesce(nullif(poa.nx_poa_gb_department_id, 0), poa.nx_poa_department_id) = #{departmentId} or poa.nx_poa_gb_department_id = #{departmentId} or poa.nx_poa_gb_department_father_id = #{departmentId} or poa.nx_poa_department_id = #{departmentId} or dor.nx_DO_gb_department_id = #{departmentId} or dor.nx_DO_gb_department_father_id = #{departmentId} )
and dor.nx_DO_apply_date = #{applyDate}
and poa.nx_poa_order_id in
#{oid}
order by dor.nx_DO_today_order asc, dor.nx_department_orders_id asc
